var techReports = new Array (
	{
        id : "wen-wifihotspot",
        name : "Wi-Fi APs as Edge Content Hotspots",
        authors : new Array(authorList.Wen, authorList.Zhi, authorList.Lifeng, authorList.Wenwu),
        journal : "Edge Video CDN: A Wi-Fi Content Hotspot Solution 2016",
		year : 2016,
		rep : 1,
		topic: "Multimedia Content Delivery",
		paperAbstract: "<p>The Internet has witnessed an explosive growth of mobile video traffic. Today, to satisfy the growing mobile video bandwidth requirement and improve quality of experience of users, a new content delivery paradigm comes into being with the emergence of smart edge-network content hotspots. These edge content hotspots are usually equipped with huge storage space (e.g., several GBs) and deployed extremely close to users (e.g., smart Wi-Fi content hotspots are usually deployed at users' homes to serve users). This new delivery paradigm, namely edge video CDN, is essentially different from both the conventional content delivery network (CDN) and the peer-to-peer (P2P) scheme, because it requires up to millions of edge hotspots located at users' homes/offices to be coordinately managed to serve mobile video content. In this paper, we explore the performance of the edge video CDN and the design space of its strategies. We perform measurement studies on how over 1.8 million users at different locations in a city request mobile video contents, and discover the heterogeneous geographical content preference, suggesting that a ``close-to-user'' video content delivery infrastructure is actually in demand; we also investigate the locations of over 1 million Wi-Fi APs in the same city, to verify the infrastructure availability---as large as 90% of mobile video users can benefit from downloading from nearby content hotspots. <p> To address the new challenges in edge video CDN, including how edge content hotspots should be organized to serve users, and how contents should be replicated to them at different locations to serve users, we propose our data-driven design as follows. First, we formulate an edge region partition problem to jointly maximize the quality experienced by users and minimize the replication cost, which is NP-hard in nature; and we design a Voronoi-like partition algorithm to generate optimal service cells. Second, to replicate contents to edge-network content hotspots, we propose an edge request prediction based replication strategy, which carries out the replication in a server peak offloading manner. We implement our design and use trace-driven experiments to verify its effectiveness. Compared with conventional centralized CDN and popularity-based replication, our design can significantly improve users' Quality of Experience (QoE) up to 40%.</p>",
    }
);

var magazineArticles = new Array (
	
	
	{
        id : "mm23-edge-immersive",
        name : "Edge Intelligence Empowered Immersive Media",
        authors : new Array(authorList.Zhi, authorList.Jiangchuan, authorList.Wenwu),
        journal : "IEEE MultiMedia, vol. 30, no. 2, pp. 8--17, April-June 2023.",
		year : 2023,
		rep : 1,
		topic: "Multimedia Edge Computing",
		paperPDF: "publications/MMUL3247574-v2.pdf",
        paperAbstract: "<p>Recent years have witnessed many immersive media services and applications, ranging from 360-degree video streaming, to augmented and virtual reality (AR and VR) and the recent metaverse experiences. These new applications usually have common features including high fidelity, immersive interaction, and open data exchange between people and the environment. As an emerging paradigm, edge computing has become increasingly ready to support these features. We first show that a key to unleashing the power of edge computing for immersive multimedia is handling AI models and data. Then, we present a framework that enables joint accuracy- and latency-aware edge intelligence, with adaptive deep learning model deployment and data streaming. We show that not only conventional mechanisms such as content placement and rate adaptation, but also the emerging 360-degree and virtual reality streaming can benefit from such edge intelligence.</p>",
        // bibitem : "<p>@inproceedings{wen-jcst2016,<br /> Author = {Wen Hu and Zhi Wang and Ming Ma and Lifeng Sun},<br /> Booktitle = {Journal of Computer Science and Technology (JCST)},<br /> Title = {{Edge Video CDN: A Wi-Fi Content Hotspot Solution}},<br /> Year = {2016}}<br /> </p>",
 	},
	
	{
        id : "mm17-peer-cdn",
        name : "Beyond 1 Million Nodes---Crowdsourced Video CDN: Architecture, Technology, and Economy",
        authors : new Array(authorList.Lifeng, authorList.Ming, authorList.Wen, authorList.Haitian, authorList.Zhi),
        journal : "IEEE MultiMedia, June 2017",
		year : 2017,
		rep : 1,
		topic: "Multimedia Content Delivery",
		paperPDF: "publications/mm17-peer-cdn.pdf",
        paperAbstract: "<p>The video service has already become one of the Internet killer applications. To deliver the ever growing video traffic with the Quality of Experience (QoE) guarantee, deploying the infrastructure of Content Delivery Network (CDN) closer and closer to users has been a noticeable trend. And this trend becomes more promising when recently CDNs providers start utilizing the storage and network resources of the edge network devices (e.g., the Wi-Fi Access Points) for content delivery [13], i.e., crowdsourced CDN. In this article, we envision the crowdsourced CDN and propose a set of practical strategies to guide the implementation of such new paradigm. Firstly, we perform a large-scale measurement to explore the geocontent popularity and the geo-heterogeneity of the resource distribution. Benefiting from the measurement observations, we design the key solutions for the system operation, including regional content popularity prediction based on Markov Decision Process (MDP), region partition for the edge device organization and the collaborative content replication. Moreover, we consider the economic issues and propose a sequential auction mechanism to cope with the resource allocation when multiple Content Providers (CPs) compete for the edge resources for their content caching. We also demonstrate the performance gain of our design with data-driven simulation.</p>",
        // bibitem : "<p>@inproceedings{wen-jcst2016,<br /> Author = {Wen Hu and Zhi Wang and Ming Ma and Lifeng Sun},<br /> Booktitle = {Journal of Computer Science and Technology (JCST)},<br /> Title = {{Edge Video CDN: A Wi-Fi Content Hotspot Solution}},<br /> Year = {2016}}<br /> </p>",
 	},
	
    {
        id : "commag-crowdsource",
        name : "Crowdsourced Road Navigation: Concept, Design, and Implementation",
        authors : new Array(authorList.Xiaoyi, authorList.Jiangchuan, authorList.Zhi, authorList.Yong, authorList.Xue),
        journal : "IEEE Communications Magazine, vol. 55, no. 6, pp. 126--128, June 2017. (<font color=\"red\">JCR-Q1</font>)",
		year : 2017,
		rep : 1,
		topic: "Multimedia Big Data",
        paperAbstract: "<p>Map services and applications have been studied extensively within the mobile computing community in the past two decades, starting from standalone GPS receivers and then moving toward connected smart terminals with live digital maps of transportation networks and even real-time traffic. More recently, with the deep penetration of modern 3G/4G networking and social networking, the crowd intelligence from the social community has been explored toward crowdsourced navigation. In this article, we first provide an overview of the past and present road navigation technologies. We then discuss very recent advances in crowd intelligence, identifying the unique challenges and opportunities therein. We further present a case study that utilizes the crowdsourced driving information to combat the last mile puzzle for road navigation.</p>",
    },
	
    {
        id : "commag-wifi",
        name : "WiFi Networks in Metropolises: From Access Point and User Perspectives",
        authors : new Array(authorList.Lei, authorList.Liting, authorList.Zhi, authorList.Jiangchuan),
        journal : "IEEE Communications Magazine, vol. 55, no. 5, pp. 42--48, May 2017. (<font color=\"red\">JCR-Q1</font>)",
		year : 2017,
		rep : 1,
		topic: "Multimedia Big Data",
        paperAbstract: "<p>Although WiFi was initially designed for providing local access to the Internet, today's expansive and explosive deployment of WiFi networks has enabled nearly ubiquitous access for mobile users in many urban areas. Yet these WiFi networks are woefully under-measured and under-instrumented during the wild expansion. We have closely collaborated with a leading network service provider to collect the massive information about wireless access points (APs) and their users in four metropolises. In this article, based on the large-scale dataset, we attempt to answer the critical questions on how the APs are deployed and how they are utilized in urban areas. In the macro-level, we depict the coverage of WiFi networks and the usage patterns, and by carefully classifying the APs, we unveil rich geographical features of today's urban WiFi networks. In the micro-level, we identify the implicit social relationships among WiFi users, and uncover the underlying social communities that are of great potentials for network optimization.</p>",
    },
	
	{
        id : "ieee-network",
        name : "Social-Aware Video Delivery: Challenges, Approaches and Directions",
        authors : new Array(authorList.Zhi, authorList.Jiangchuan, authorList.Wenwu),
        journal : "IEEE Network Magazine, vol. 30, no. 5, pp. 35--39, September 2016. (<font color=\"red\">JCR-Q1</font>)",
		year : 2016,
		rep : 1,
		topic: "Multimedia Content Delivery",
		paperPDF : "publications/zhi-ieee-network-1.pdf",
        paperAbstract: "<p>We have recently witnessed the convergence of online social network services and online video services: users import videos from content sharing sites, and propagate them along the social connections by re-sharing them. Such social behaviors have dramatically reshaped how videos are disseminated, and the users are now actively engaged to be part of the social ecosystem, rather than being passively consumers. Despite the increasingly abundant bandwidth and computation resources, the ever increasing data volume of user generated video content and the boundless coverage of socialized sharing have presented unprecedented challenges. This article first presents the challenges in social-aware video delivery. Then, we present a principal framework for social-aware video delivery and state-of-the-art overview of approaches. Moreover, we identify the unique characteristics of social-aware video access and the social content propagation, and closely reveal the design of individual modules and their integration towards enhancing users' experience in the social network context. Finally，we discuss future research directions.</p>",
		bibitem: "<p>@article{zhi-ieee-network,<br />	Author = {Wang, Zhi and Liu, Jiangchuan and Zhu, Wenwu},<br />	Journal = {IEEE Network},<br />	Title = {Social-Aware Video Delivery: Challenges, Approaches and Directions},<br />	Year = {2015}}</p>",
    },
    
	{
        id : "ieee-mm-mmbigdatacomputing",
        name : "Multimedia Big Data Computing",
        authors : new Array(authorList.Wenwu, authorList.Peng, authorList.Zhi, authorList.Gang),
        journal : "IEEE MultiMedia, vol. 22, no. 3, pp. 96--c3, July 2015.",
		year : 2015,
		rep : 1,
		topic: "Multimedia Big Data", 
		paperPDF : "publications/wenwu-mmmagzine15-0.pdf",
        paperAbstract: "<p>With the proliferation of the Internet, various sensors including mobile phones and cameras, as well as social media, huge amount of multimedia data has been generated, forming multimedia big data. However, since multimedia data is unstructured with multi-modality in nature, and is of real-time and Quality of Experience (QoE) requirements, multimedia big data computing has not only created unprecedented opportunities but also imposed fundamental challenges to multimedia storage, processing, analysis, systems, etc. In this paper, we present the principal concept for multimedia big data computing, introduce what the scientific problems and fundamental challenges for multimedia media big data computing are, present methodologies and approaches for multimedia big data computing, in terms of multimedia big data computing lifecycle: data -> information -> knowledge -> decision. Finally, we introduce the research opportunities and directions for multimedia big data computing.</p>",
		bibitem: "<p>@article{wenwu-mmmagzine15,<br />	Author = {Wenwu Zhu and Peng Cui and Zhi Wang and Gang Hua},<br />	Journal = {IEEE MultiMedia},<br />	Title = {Multimedia Big Data Computing},<br />	Year = {2015}}</p>",
    }
);

